const ERROR_ROWS = {
  "sr-Latn": `Meni sa tim nazivom već postoji.|Meni nije pronađen.|Neispravan ID menija.|Nadređena stavka menija ne postoji.|Izabrana stavka sadržaja ne postoji.|Izabrana kategorija ne postoji.|Mogu se povezati samo kategorije blog objava.|URL se ne može uređivati za povezane stavke -- prati povezani sadržaj ili kategoriju.|Otkriven je ciklus u hijerarhiji menija.|Stavka menija nije pronađena.|Naziv menija je obavezan.|Izabrana stavka menija ne postoji.|Izabrana nadređena stavka menija ne postoji.|Stavka ne može biti sopstveni roditelj.|Vlasnik je obavezan.|Ciljni korisnik mora biti backend korisnik.`,
  "sr-Cyrl": `Мени са тим називом већ постоји.|Мени није пронађен.|Неисправан ID менија.|Надређена ставка менија не постоји.|Изабрана ставка садржаја не постоји.|Изабрана категорија не постоји.|Могу се повезати само категорије блог објава.|URL се не може уређивати за повезане ставке -- прати повезани садржај или категорију.|Откривен је циклус у хијерархији менија.|Ставка менија није пронађена.|Назив менија је обавезан.|Изабрана ставка менија не постоји.|Изабрана надређена ставка менија не постоји.|Ставка не може бити сопствени родитељ.|Власник је обавезан.|Циљни корисник мора бити backend корисник.`,
  hr: `Izbornik s tim nazivom već postoji.|Izbornik nije pronađen.|Neispravan ID izbornika.|Nadređena stavka izbornika ne postoji.|Odabrana stavka sadržaja ne postoji.|Odabrana kategorija ne postoji.|Mogu se povezati samo kategorije blog objava.|URL se ne može uređivati za povezane stavke -- prati povezani sadržaj ili kategoriju.|Otkriven je ciklus u hijerarhiji izbornika.|Stavka izbornika nije pronađena.|Naziv izbornika je obavezan.|Odabrana stavka izbornika ne postoji.|Odabrana nadređena stavka izbornika ne postoji.|Stavka ne može biti vlastiti roditelj.|Vlasnik je obavezan.|Ciljni korisnik mora biti backend korisnik.`,
  de: `Ein Menü mit diesem Namen existiert bereits.|Menü nicht gefunden.|Ungültige Menü-ID.|Übergeordneter Menüeintrag existiert nicht.|Ausgewähltes Inhaltselement existiert nicht.|Ausgewählte Kategorie existiert nicht.|Es können nur Blogbeitragskategorien verlinkt werden.|Die URL kann für verknüpfte Einträge nicht bearbeitet werden -- sie folgt dem verknüpften Inhalt oder der Kategorie.|Zyklus in der Menühierarchie erkannt.|Menüeintrag nicht gefunden.|Menüname ist erforderlich.|Ausgewählter Menüeintrag existiert nicht.|Ausgewählter übergeordneter Menüeintrag existiert nicht.|Ein Eintrag kann nicht sein eigener Elternknoten sein.|Besitzer ist erforderlich.|Der Zielbenutzer muss ein Backend-Benutzer sein.`,
  fr: `Un menu portant ce nom existe déjà.|Menu introuvable.|ID de menu invalide.|L'élément de menu parent n'existe pas.|L'élément de contenu sélectionné n'existe pas.|La catégorie sélectionnée n'existe pas.|Seules les catégories d'articles de blog peuvent être liées.|L'URL ne peut pas être modifiée pour les éléments liés -- elle suit le contenu ou la catégorie liée.|Cycle détecté dans la hiérarchie du menu.|Élément de menu introuvable.|Le nom du menu est obligatoire.|L'élément de menu sélectionné n'existe pas.|L'élément de menu parent sélectionné n'existe pas.|Un élément ne peut pas être son propre parent.|Le propriétaire est obligatoire.|L'utilisateur cible doit être un utilisateur backend.`,
  es: `Ya existe un menú con ese nombre.|Menú no encontrado.|ID de menú no válido.|El elemento de menú padre no existe.|El elemento de contenido seleccionado no existe.|La categoría seleccionada no existe.|Solo se pueden enlazar categorías de entradas de blog.|La URL no se puede editar en elementos vinculados -- sigue el contenido o la categoría vinculada.|Se detectó un ciclo en la jerarquía del menú.|Elemento de menú no encontrado.|El nombre del menú es obligatorio.|El elemento de menú seleccionado no existe.|El elemento de menú padre seleccionado no existe.|Un elemento no puede ser su propio padre.|El propietario es obligatorio.|El usuario de destino debe ser un usuario backend.`,
  it: `Esiste già un menu con questo nome.|Menu non trovato.|ID menu non valido.|L'elemento di menu padre non esiste.|L'elemento di contenuto selezionato non esiste.|La categoria selezionata non esiste.|È possibile collegare solo categorie di post del blog.|L'URL non può essere modificato per gli elementi collegati -- segue il contenuto o la categoria collegata.|Rilevato un ciclo nella gerarchia del menu.|Elemento di menu non trovato.|Il nome del menu è obbligatorio.|L'elemento di menu selezionato non esiste.|L'elemento di menu padre selezionato non esiste.|Un elemento non può essere il proprio genitore.|Il proprietario è obbligatorio.|L'utente di destinazione deve essere un utente backend.`,
  pt: `Já existe um menu com esse nome.|Menu não encontrado.|ID de menu inválido.|O item de menu pai não existe.|O item de conteúdo selecionado não existe.|A categoria selecionada não existe.|Só podem ser ligadas categorias de publicações de blog.|O URL não pode ser editado em itens ligados -- segue o conteúdo ou a categoria ligada.|Foi detetado um ciclo na hierarquia do menu.|Item de menu não encontrado.|O nome do menu é obrigatório.|O item de menu selecionado não existe.|O item de menu pai selecionado não existe.|Um item não pode ser o seu próprio pai.|O proprietário é obrigatório.|O utilizador de destino tem de ser um utilizador backend.`,
  "pt-BR": `Já existe um menu com esse nome.|Menu não encontrado.|ID de menu inválido.|O item de menu pai não existe.|O item de conteúdo selecionado não existe.|A categoria selecionada não existe.|Só é possível vincular categorias de posts do blog.|A URL não pode ser editada para itens vinculados -- ela segue o conteúdo ou a categoria vinculada.|Foi detectado um ciclo na hierarquia do menu.|Item de menu não encontrado.|O nome do menu é obrigatório.|O item de menu selecionado não existe.|O item de menu pai selecionado não existe.|Um item não pode ser seu próprio pai.|O proprietário é obrigatório.|O usuário de destino deve ser um usuário backend.`,
  nl: `Er bestaat al een menu met die naam.|Menu niet gevonden.|Ongeldige menu-ID.|Bovenliggend menu-item bestaat niet.|Geselecteerd inhoudsitem bestaat niet.|Geselecteerde categorie bestaat niet.|Alleen blogberichtcategorieën kunnen worden gelinkt.|De URL kan niet worden bewerkt voor gekoppelde items -- deze volgt de gekoppelde inhoud of categorie.|Cyclus gedetecteerd in de menuhierarchie.|Menu-item niet gevonden.|Menunaam is verplicht.|Geselecteerd menu-item bestaat niet.|Geselecteerd bovenliggend menu-item bestaat niet.|Een item kan niet zijn eigen ouder zijn.|Eigenaar is verplicht.|De doelgebruiker moet een backend-gebruiker zijn.`,
  pl: `Menu o tej nazwie już istnieje.|Nie znaleziono menu.|Nieprawidłowy identyfikator menu.|Nadrzędna pozycja menu nie istnieje.|Wybrany element treści nie istnieje.|Wybrana kategoria nie istnieje.|Można linkować tylko kategorie wpisów bloga.|Nie można edytować URL dla powiązanych pozycji -- podąża za powiązaną treścią lub kategorią.|Wykryto cykl w hierarchii menu.|Nie znaleziono pozycji menu.|Nazwa menu jest wymagana.|Wybrana pozycja menu nie istnieje.|Wybrana nadrzędna pozycja menu nie istnieje.|Pozycja nie może być własnym rodzicem.|Właściciel jest wymagany.|Docelowy użytkownik musi być użytkownikiem backendu.`,
  tr: `Bu ada sahip bir menü zaten var.|Menü bulunamadı.|Geçersiz menü kimliği.|Üst menü öğesi mevcut değil.|Seçilen içerik öğesi mevcut değil.|Seçilen kategori mevcut değil.|Yalnızca blog gönderisi kategorileri bağlanabilir.|Bağlı öğeler için URL düzenlenemez -- bağlı içerik veya kategoriyi izler.|Menü hiyerarşisinde döngü algılandı.|Menü öğesi bulunamadı.|Menü adı gereklidir.|Seçilen menü öğesi mevcut değil.|Seçilen üst menü öğesi mevcut değil.|Bir öğe kendi ebeveyni olamaz.|Sahip gereklidir.|Hedef kullanıcı bir backend kullanıcısı olmalıdır.`,
  mk: `Мени со тоа име веќе постои.|Менито не е пронајдено.|Невалиден ID на мени.|Надредената ставка од менито не постои.|Избраната ставка со содржина не постои.|Избраната категорија не постои.|Може да се поврзуваат само категории на блог објави.|URL-то не може да се уредува за поврзани ставки -- го следи поврзаниот содржај или категорија.|Откриен е циклус во хиерархијата на менито.|Ставката од менито не е пронајдена.|Името на менито е задолжително.|Избраната ставка од менито не постои.|Избраната надредена ставка од менито не постои.|Ставка не може да биде сопствен родител.|Сопственикот е задолжителен.|Целниот корисник мора да биде backend корисник.`,
  bs: `Meni s tim nazivom već postoji.|Meni nije pronađen.|Neispravan ID menija.|Nadređena stavka menija ne postoji.|Izabrana stavka sadržaja ne postoji.|Izabrana kategorija ne postoji.|Mogu se povezati samo kategorije blog objava.|URL se ne može uređivati za povezane stavke -- prati povezani sadržaj ili kategoriju.|Otkriven je ciklus u hijerarhiji menija.|Stavka menija nije pronađena.|Naziv menija je obavezan.|Izabrana stavka menija ne postoji.|Izabrana nadređena stavka menija ne postoji.|Stavka ne može biti vlastiti roditelj.|Vlasnik je obavezan.|Ciljni korisnik mora biti backend korisnik.`,
  sl: `Meni s tem imenom že obstaja.|Meni ni najden.|Neveljaven ID menija.|Nadrejeni element menija ne obstaja.|Izbrani element vsebine ne obstaja.|Izbrana kategorija ne obstaja.|Povezati je mogoče samo kategorije blog objav.|URL-ja ni mogoče urejati za povezane elemente -- sledi povezani vsebini ali kategoriji.|Zaznan je cikel v hierarhiji menija.|Element menija ni najden.|Ime menija je obvezno.|Izbrani element menija ne obstaja.|Izbrani nadrejeni element menija ne obstaja.|Element ne more biti svoj starš.|Lastnik je obvezen.|Ciljni uporabnik mora biti backend uporabnik.`,
  ru: `Меню с таким названием уже существует.|Меню не найдено.|Недопустимый ID меню.|Родительский пункт меню не существует.|Выбранный элемент содержимого не существует.|Выбранная категория не существует.|Можно связывать только категории записей блога.|URL нельзя редактировать для связанных элементов -- он следует связанному содержимому или категории.|Обнаружен цикл в иерархии меню.|Пункт меню не найден.|Название меню обязательно.|Выбранный пункт меню не существует.|Выбранный родительский пункт меню не существует.|Элемент не может быть собственным родителем.|Владелец обязателен.|Целевой пользователь должен быть backend-пользователем.`,
  hu: `Ilyen nevű menü már létezik.|A menü nem található.|Érvénytelen menüazonosító.|A szülő menüelem nem létezik.|A kiválasztott tartalomelem nem létezik.|A kiválasztott kategória nem létezik.|Csak blogbejegyzés-kategóriák kapcsolhatók.|A kapcsolt elemek URL-je nem szerkeszthető -- a kapcsolt tartalmat vagy kategóriát követi.|Ciklus észlelve a menühierarchiában.|A menüelem nem található.|A menü neve kötelező.|A kiválasztott menüelem nem létezik.|A kiválasztott szülő menüelem nem létezik.|Egy elem nem lehet a saját szülője.|Tulajdonos megadása kötelező.|A célfelhasználónak backend-felhasználónak kell lennie.`,
  bg: `Вече съществува меню с това име.|Менюто не е намерено.|Невалиден ID на меню.|Родителският елемент от менюто не съществува.|Избраният елемент със съдържание не съществува.|Избраната категория не съществува.|Могат да се свързват само категории на блог публикации.|URL адресът не може да се редактира за свързани елементи -- следва свързаното съдържание или категория.|Открит е цикъл в йерархията на менюто.|Елементът от менюто не е намерен.|Името на менюто е задължително.|Избраният елемент от менюто не съществува.|Избраният родителски елемент от менюто не съществува.|Елемент не може да бъде собствен родител.|Собственикът е задължителен.|Целевият потребител трябва да бъде backend потребител.`,
  ja: `その名前のメニューは既に存在します。|メニューが見つかりません。|メニュー ID が無効です。|親メニュー項目が存在しません。|選択したコンテンツ項目が存在しません。|選択したカテゴリが存在しません。|リンクできるのはブログ記事カテゴリのみです。|リンク済み項目の URL は編集できません -- リンクされたコンテンツまたはカテゴリに従います。|メニュー階層で循環が検出されました。|メニュー項目が見つかりません。|メニュー名は必須です。|選択したメニュー項目が存在しません。|選択した親メニュー項目が存在しません。|項目を自分自身の親にすることはできません。|所有者は必須です。|対象ユーザーは backend ユーザーである必要があります。`,
  "zh-Hans": `已存在同名菜单。|未找到菜单。|菜单 ID 无效。|父菜单项不存在。|所选内容项不存在。|所选分类不存在。|只能链接博客文章分类。|关联项的 URL 无法编辑 -- 它会跟随关联内容或分类。|菜单层级中检测到循环。|未找到菜单项。|菜单名称为必填项。|所选菜单项不存在。|所选父菜单项不存在。|项目不能作为自己的父项。|所有者为必填项。|目标用户必须是 backend 用户。`,
  "zh-Hant": `已存在同名選單。|找不到選單。|選單 ID 無效。|父層選單項目不存在。|所選內容項目不存在。|所選分類不存在。|只能連結部落格文章分類。|連結項目的 URL 無法編輯 -- 它會跟隨連結內容或分類。|選單階層中偵測到循環。|找不到選單項目。|選單名稱為必填。|所選選單項目不存在。|所選父層選單項目不存在。|項目不能作為自己的父項。|擁有者為必填。|目標使用者必須是 backend 使用者。`,
  ar: `توجد قائمة بهذا الاسم بالفعل.|لم يتم العثور على القائمة.|معرّف القائمة غير صالح.|عنصر القائمة الأب غير موجود.|عنصر المحتوى المحدد غير موجود.|الفئة المحددة غير موجودة.|يمكن ربط فئات منشورات المدونة فقط.|لا يمكن تعديل عنوان URL للعناصر المرتبطة -- فهو يتبع المحتوى أو الفئة المرتبطة.|تم اكتشاف حلقة في تسلسل القائمة.|لم يتم العثور على عنصر القائمة.|اسم القائمة مطلوب.|عنصر القائمة المحدد غير موجود.|عنصر القائمة الأب المحدد غير موجود.|لا يمكن أن يكون العنصر أبا لنفسه.|المالك مطلوب.|يجب أن يكون المستخدم الهدف مستخدم backend.`,
  id: `Menu dengan nama itu sudah ada.|Menu tidak ditemukan.|ID menu tidak valid.|Item menu induk tidak ada.|Item konten yang dipilih tidak ada.|Kategori yang dipilih tidak ada.|Hanya kategori posting blog yang dapat ditautkan.|URL tidak dapat diedit untuk item tertaut -- URL mengikuti konten atau kategori tertaut.|Siklus terdeteksi dalam hierarki menu.|Item menu tidak ditemukan.|Nama menu wajib diisi.|Item menu yang dipilih tidak ada.|Item menu induk yang dipilih tidak ada.|Item tidak dapat menjadi induknya sendiri.|Pemilik wajib diisi.|Pengguna target harus menjadi pengguna backend.`,
  cs: `Menu s tímto názvem již existuje.|Menu nebylo nalezeno.|Neplatné ID menu.|Nadřazená položka menu neexistuje.|Vybraná položka obsahu neexistuje.|Vybraná kategorie neexistuje.|Lze propojit pouze kategorie blogových příspěvků.|URL nelze u propojených položek upravit -- následuje propojený obsah nebo kategorii.|V hierarchii menu byl zjištěn cyklus.|Položka menu nebyla nalezena.|Název menu je povinný.|Vybraná položka menu neexistuje.|Vybraná nadřazená položka menu neexistuje.|Položka nemůže být sama sobě nadřazená.|Vlastník je povinný.|Cílový uživatel musí být backend uživatel.`,
  ro: `Există deja un meniu cu acest nume.|Meniul nu a fost găsit.|ID meniu nevalid.|Elementul de meniu părinte nu există.|Elementul de conținut selectat nu există.|Categoria selectată nu există.|Pot fi legate doar categoriile de articole blog.|URL-ul nu poate fi editat pentru elementele legate -- urmează conținutul sau categoria legată.|A fost detectat un ciclu în ierarhia meniului.|Elementul de meniu nu a fost găsit.|Numele meniului este obligatoriu.|Elementul de meniu selectat nu există.|Elementul de meniu părinte selectat nu există.|Un element nu poate fi propriul părinte.|Proprietarul este obligatoriu.|Utilizatorul țintă trebuie să fie utilizator backend.`,
  el: `Υπάρχει ήδη μενού με αυτό το όνομα.|Το μενού δεν βρέθηκε.|Μη έγκυρο ID μενού.|Το γονικό στοιχείο μενού δεν υπάρχει.|Το επιλεγμένο στοιχείο περιεχομένου δεν υπάρχει.|Η επιλεγμένη κατηγορία δεν υπάρχει.|Μπορούν να συνδεθούν μόνο κατηγορίες άρθρων blog.|Το URL δεν μπορεί να επεξεργαστεί για συνδεδεμένα στοιχεία -- ακολουθεί το συνδεδεμένο περιεχόμενο ή κατηγορία.|Εντοπίστηκε κύκλος στην ιεραρχία του μενού.|Το στοιχείο μενού δεν βρέθηκε.|Το όνομα μενού είναι υποχρεωτικό.|Το επιλεγμένο στοιχείο μενού δεν υπάρχει.|Το επιλεγμένο γονικό στοιχείο μενού δεν υπάρχει.|Ένα στοιχείο δεν μπορεί να είναι γονέας του εαυτού του.|Ο ιδιοκτήτης είναι υποχρεωτικός.|Ο χρήστης στόχος πρέπει να είναι χρήστης backend.`,
  da: `Der findes allerede en menu med det navn.|Menuen blev ikke fundet.|Ugyldigt menu-ID.|Overordnet menupunkt findes ikke.|Det valgte indholdselement findes ikke.|Den valgte kategori findes ikke.|Kun blogindlægskategorier kan linkes.|URL'en kan ikke redigeres for linkede elementer -- den følger det linkede indhold eller den linkede kategori.|Der blev fundet en cyklus i menuhierarkiet.|Menupunkt blev ikke fundet.|Menunavn er påkrævet.|Det valgte menupunkt findes ikke.|Det valgte overordnede menupunkt findes ikke.|Et element kan ikke være sin egen forælder.|Ejer er påkrævet.|Målbrugeren skal være en backend-bruger.`,
  sv: `Det finns redan en meny med det namnet.|Menyn hittades inte.|Ogiltigt meny-ID.|Överordnat menyalternativ finns inte.|Det valda innehållsobjektet finns inte.|Den valda kategorin finns inte.|Endast bloggpostkategorier kan länkas.|URL:en kan inte redigeras för länkade objekt -- den följer det länkade innehållet eller kategorin.|En cykel upptäcktes i menyhierarkin.|Menyalternativ hittades inte.|Menynamn krävs.|Det valda menyalternativet finns inte.|Det valda överordnade menyalternativet finns inte.|Ett objekt kan inte vara sin egen förälder.|Ägare krävs.|Målanvändaren måste vara en backend-användare.`,
  nb: `Det finnes allerede en meny med det navnet.|Menyen ble ikke funnet.|Ugyldig meny-ID.|Overordnet menyelement finnes ikke.|Valgt innholdselement finnes ikke.|Valgt kategori finnes ikke.|Bare blogginnleggskategorier kan lenkes.|URL-en kan ikke redigeres for lenkede elementer -- den følger lenket innhold eller kategori.|Det ble oppdaget en syklus i menyhierarkiet.|Menyelementet ble ikke funnet.|Menynavn er påkrevd.|Valgt menyelement finnes ikke.|Valgt overordnet menyelement finnes ikke.|Et element kan ikke være sin egen forelder.|Eier er påkrevd.|Målbrukeren må være en backend-bruker.`,
  nn: `Det finst allereie ein meny med det namnet.|Menyen vart ikkje funnen.|Ugyldig meny-ID.|Overordna menyelement finst ikkje.|Valt innhaldselement finst ikkje.|Vald kategori finst ikkje.|Berre blogginnleggskategoriar kan lenkjast.|URL-en kan ikkje redigerast for lenkja element -- han følgjer lenkja innhald eller kategori.|Det vart oppdaga ein syklus i menyhierarkiet.|Menyelementet vart ikkje funne.|Menynamn er påkravd.|Valt menyelement finst ikkje.|Valt overordna menyelement finst ikkje.|Eit element kan ikkje vere sin eigen forelder.|Eigar er påkravd.|Målbrukaren må vere ein backend-brukar.`,
  fi: `Samanniminen valikko on jo olemassa.|Valikkoa ei löytynyt.|Virheellinen valikon ID.|Ylätason valikkokohdetta ei ole olemassa.|Valittua sisältökohdetta ei ole olemassa.|Valittua kategoriaa ei ole olemassa.|Vain blogiartikkelien kategorioita voidaan linkittää.|URL-osoitetta ei voi muokata linkitetyille kohteille -- se seuraa linkitettyä sisältöä tai kategoriaa.|Valikkohierarkiassa havaittiin silmukka.|Valikkokohdetta ei löytynyt.|Valikon nimi on pakollinen.|Valittua valikkokohdetta ei ole olemassa.|Valittua ylätason valikkokohdetta ei ole olemassa.|Kohde ei voi olla oma ylätasonsa.|Omistaja on pakollinen.|Kohdekäyttäjän on oltava backend-käyttäjä.`,
  is: `Valmynd með þessu nafni er þegar til.|Valmynd fannst ekki.|Ógilt auðkenni valmyndar.|Yfirvalmyndaratriði er ekki til.|Valið efnisatriði er ekki til.|Valinn flokkur er ekki til.|Aðeins er hægt að tengja flokka bloggfærslna.|Ekki er hægt að breyta slóð fyrir tengd atriði -- hún fylgir tengdu efni eða flokki.|Hringur fannst í stigveldi valmyndar.|Valmyndaratriði fannst ekki.|Nafn valmyndar er nauðsynlegt.|Valið valmyndaratriði er ekki til.|Valið yfirvalmyndaratriði er ekki til.|Atriði getur ekki verið eigið foreldri.|Eigandi er nauðsynlegur.|Marknotandi verður að vera backend-notandi.`,
} satisfies Record<LocalizedLanguage, string>;

function createMap(
  language: string,
  row: string,
): Record<MenuManagementSource, string> {
  const translations = row.split("|");
  if (translations.length !== MENU_MANAGEMENT_SOURCE_STRINGS.length) {
    throw new Error(
      `${language} menu management translations must have ${MENU_MANAGEMENT_SOURCE_STRINGS.length} entries, received ${translations.length}.`,
    );
  }

  return Object.fromEntries(
    MENU_MANAGEMENT_SOURCE_STRINGS.map((source, index) => [
      source,
      translations[index] ?? source,
    ]),
  ) as Record<MenuManagementSource, string>;
}

function createErrorMap(
  language: string,
  row: string,
): Record<MenuManagementErrorSource, string> {
  const translations = row.split("|");
  if (translations.length !== MENU_MANAGEMENT_ERROR_SOURCE_STRINGS.length) {
    throw new Error(
      `${language} menu management error translations must have ${MENU_MANAGEMENT_ERROR_SOURCE_STRINGS.length} entries, received ${translations.length}.`,
    );
  }

  return Object.fromEntries(
    MENU_MANAGEMENT_ERROR_SOURCE_STRINGS.map((source, index) => [
      source,
      translations[index] ?? source,
    ]),
  ) as Record<MenuManagementErrorSource, string>;
}

export const MENU_MANAGEMENT_SOURCE_TRANSLATIONS = Object.fromEntries(
  Object.entries(ROWS).map(([language, row]) => [
    language,
    {
      ...createMap(language, row),
      ...createErrorMap(language, ERROR_ROWS[language as LocalizedLanguage]),
    },
  ]),
) as Record<
  LocalizedLanguage,
  Record<MenuManagementSource | MenuManagementErrorSource, string>
>;
